create table dirkspzm32.isi_res_pruef_plan_data_cfg (
    sid                     varchar2(2 char) not null enable,
    firma_nr                number(6, 0) not null enable,
    res_id                  number(*, 0) not null enable,
    res_teilgewerk          number(*, 5) not null enable,
    res_pruef_plan_data_nr  number(*, 5) not null enable,
    res_pruef_plan_data_bez varchar2(500 char) not null enable,
    created_date            date not null enable,
    created_login_id        number(*, 0),
    last_change_date        date,
    last_change_login_id    number(*, 0),
    id                      number(*, 0) not null enable,
    daten_faktor            number(*, 5) default 1,
    einheit                 varchar2(10 char)
);

alter table dirkspzm32.isi_res_pruef_plan_data_cfg
    add constraint pk_isi_res_pruef_plan_data_cfg primary key ( id )
        using index enable;


